import { Component, OnInit } from '@angular/core';
import { Student, StudentService } from '../../../core/services/student.service';
import { GradeService } from '../../../core/services/grade.service';
import { NotificationService } from '../../../core/services/notification.service';

@Component({
  selector: 'app-bulletin',
  templateUrl: './bulletin.component.html',
  styleUrls: ['./bulletin.component.css']
})
export class BulletinComponent implements OnInit {
  students: Student[] = [];
  selectedStudent: Student | null = null;
  grades: any[] = [];
  selectedTerm = '';
  terms = ['Trimestre 1', 'Trimestre 2', 'Trimestre 3'];
  loading = false;

  constructor(
    private studentService: StudentService,
    private gradeService: GradeService,
    private notification: NotificationService
  ) {}

  ngOnInit() {
    this.studentService.getAll().subscribe(s => this.students = s);
  }

  loadGrades() {
    if (!this.selectedStudent) return;
    this.loading = true;
    this.gradeService.getByStudent(this.selectedStudent.id!).subscribe({
      next: (grades) => {
        if (this.selectedTerm) {
          this.grades = grades.filter(g => g.term === this.selectedTerm);
        } else {
          this.grades = grades;
        }
        this.loading = false;
      },
      error: () => this.loading = false
    });
  }

  calculateAverage(): number {
    if (this.grades.length === 0) return 0;
    const sum = this.grades.reduce((acc, g) => acc + g.score, 0);
    return sum / this.grades.length;
  }

  generateBulletin() {
    if (!this.selectedStudent) {
      this.notification.warning('Sélectionnez un étudiant');
      return;
    }
    this.notification.success('Bulletin généré avec succès');
    // Ici on pourrait implémenter l'export PDF
  }

  generateAllBulletins() {
    this.notification.info('Génération de tous les bulletins en cours...');
    setTimeout(() => {
      this.notification.success(`${this.students.length} bulletins générés`);
    }, 2000);
  }
}
